// Compliant: Split into smaller functions
bool isValidItem(int item) {
    return item >= 0 && item <= 1000;
}

int processItem(int item) {
    return item * 2 + 1;
}

cppcoro::task<int> processData(const std::vector<int>& data) {
    int result = 0;
    for (auto item : data) {
        if (!isValidItem(item)) continue;
        int processed = processItem(item);
        result += processed;
        co_yield processed;
    }
    co_return result;
}
